**TASK 11: QR Scan Validation Edge Function**

**Step 4: Create validate-scan Edge Function**
Create `supabase/functions/validate-scan/index.ts`:
```typescript
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL')!,
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
    );

    const authHeader = req.headers.get('Authorization');
    if (!authHeader) return new Response(JSON.stringify({ error: 'No auth' }), { status: 401, headers: corsHeaders });

    const { data: { user }, error: authError } = await supabase.auth.getUser(authHeader.replace('Bearer ', ''));
    if (authError || !user) return new Response(JSON.stringify({ error: 'Unauthorized' }), { status: 401, headers: corsHeaders });

    const { qr_id, secret } = await req.json();

    // Validate QR code
    const { data: qrCode, error: qrError } = await supabase
      .from('qr_codes')
      .select('*, loyalty_programs(*)')
      .eq('id', qr_id)
      .eq('secret_key', secret)
      .eq('is_active', true)
      .single();

    if (qrError || !qrCode) return new Response(JSON.stringify({ error: 'Invalid QR code' }), { status: 400, headers: corsHeaders });

    const program = qrCode.loyalty_programs;

    // Get or create customer card
    let { data: card } = await supabase
      .from('customer_cards')
      .select('*')
      .eq('customer_id', user.id)
      .eq('program_id', program.id)
      .single();

    if (!card) {
      const { data: existingCustomer } = await supabase.from('customers').select('id').eq('id', user.id).single();
      if (!existingCustomer) {
        await supabase.from('customers').insert({ id: user.id, email: user.email! });
      }
      const { data: newCard } = await supabase
        .from('customer_cards')
        .insert({ customer_id: user.id, program_id: program.id })
        .select()
        .single();
      card = newCard;
    }

    if (!card) return new Response(JSON.stringify({ error: 'Could not create card' }), { status: 500, headers: corsHeaders });

    // Add stamp or points
    let transactionType: string;
    let value: number;

    if (program.type === 'stamp') {
      transactionType = 'stamp_add';
      value = 1;
      await supabase.from('customer_cards').update({
        current_stamps: card.current_stamps + 1,
        last_activity: new Date().toISOString(),
      }).eq('id', card.id);
    } else {
      transactionType = 'points_add';
      value = program.points_per_euro || 1;
      await supabase.from('customer_cards').update({
        current_points: card.current_points + value,
        last_activity: new Date().toISOString(),
      }).eq('id', card.id);
    }

    // Record transaction
    await supabase.from('transactions').insert({
      card_id: card.id,
      type: transactionType,
      value,
      validated_by: 'qr',
    });

    return new Response(JSON.stringify({
      success: true,
      program_name: program.name,
      type: program.type,
      added: value,
      new_total: program.type === 'stamp' ? card.current_stamps + 1 : card.current_points + value,
      goal: program.type === 'stamp' ? program.stamp_goal : null,
    }), { status: 200, headers: { ...corsHeaders, 'Content-Type': 'application/json' } });

  } catch (err) {
    return new Response(JSON.stringify({ error: (err as Error).message }), { status: 500, headers: corsHeaders });
  }
});
```

